from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
import json

app = Flask(__name__)

# In-memory storage for labels
labels = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data.get('image_id')
    label = data.get('label')
    annotator_id = data.get('annotator_id')

    if not image_id or not label or not annotator_id:
        return jsonify({'error': 'Invalid input'}), 400

    # Store the label with the annotator ID
    labels[image_id].append({'label': label, 'annotator_id': annotator_id})
    return jsonify({'message': 'Label submitted successfully'}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, entries in labels.items():
        votes = defaultdict(int)
        for entry in entries:
            votes[entry['label']] += 1
        # Majority voting
        majority_label = max(votes, key=votes.get)
        aggregated_labels[image_id] = majority_label
    return jsonify(aggregated_labels), 200

@app.route('/train', methods=['POST'])
def train_model():
    # Placeholder for model training logic
    # Here we would train the model using the aggregated labels
    return jsonify({'message': 'Model trained successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)